sql:
SELECT media_title, upload_date
FROM media_sources
ORDER BY upload_date DESC;

SELECT COUNT(media_id) AS media_count
FROM media_sources
WHERE created_by = 123;

SELECT DISTINCT upload_date
FROM media_sources
ORDER BY upload_date DESC;

